  <div id="modal_ps" class="modal fade"><div class="modal-dialog modal-lg" style="width:96%"><form id="form_ps" class="modal-content ps-form"><input type="hidden" name="submit" id="ps_submit" value="N"><div class="modal-header"><button class="close" data-dismiss="modal">&times;</button><h4 class="modal-title">Create Production Schedule</h4></div><div class="modal-body"><div class="row"><div class="col-md-7 form-group"><label class="required-label"><?=prod_h('production_order', 'Production Order');?></label><select id="ps_production_id" name="production_id" class="form-control" required></select><div class="ps-help">Hanya Production Order RELEASED/IN_PROCESS yang bisa dijadwalkan.</div></div><div class="col-md-2 form-group"><label class="required-label">Schedule Date</label><input name="schedule_date" id="ps_schedule_date" class="form-control ps-date-input" value="<?=date('Y-m-d');?>"></div><div class="col-md-3 form-group"><label>Scheduler</label><input name="scheduler" class="form-control" value="<?=htmlspecialchars(isset($_SESSION['username'])?$_SESSION['username']:'',ENT_QUOTES,'UTF-8');?>"></div></div><div class="row"><div class="col-md-3 form-group"><label>Planned Start</label><input type="datetime-local" name="planned_start" id="ps_planned_start" class="form-control" value="<?=date('Y-m-d');?>T08:00"></div><div class="col-md-3 form-group"><label>Planned Finish</label><input type="datetime-local" name="planned_finish" id="ps_planned_finish" class="form-control" value="<?=date('Y-m-d');?>T17:00"></div><div class="col-md-6 form-group"><label><?=prod_h('common_remarks', 'Remarks');?></label><input name="remarks" class="form-control" placeholder="Catatan dispatch, kapasitas, constraint mesin, dll"></div></div><div class="clearfix"><h4 class="pull-left">Operation Schedule</h4><button type="button" id="btn_reload_ops_ps" class="btn btn-default btn-sm pull-right"><i class="fa fa-refresh"></i> Reload Operations</button></div><div id="ps_ops_area" class="ps-op-wrap"><div class="alert alert-info" style="margin:12px">Pilih Production Order untuk menampilkan operation.</div></div></div><div class="modal-footer"><button type="button" class="btn btn-default" data-dismiss="modal"><?=prod_h('common_close', 'Close');?></button><button type="button" id="btn_save_draft_ps" class="btn btn-default"><i class="fa fa-save"></i> Save Draft</button><button type="button" id="btn_submit_ps" class="btn btn-primary"><i class="fa fa-calendar-check-o"></i> Save & Schedule</button></div></form></div></div>
