<script src="<?=base_admin();?>assets/plugins/select2/select2.min.js"></script><script src="https://cdn.jsdelivr.net/npm/sweetalert2@11"></script>
<script>
function psError(m){$('.isi_warning_delete').text(m||<?=prod_js('production_schedule_process_failed', 'Production Schedule failed to process.');?>);$('.error_data_delete').fadeIn();}
function psFilters(){return{tgl_awal:$('#filter_tgl_awal').val(),tgl_akhir:$('#filter_tgl_akhir').val(),status:$('#filter_status').val(),plant:$('#filter_plant').val(),work_center:$('#filter_work_center').val(),keyword:$('#filter_keyword').val()};}
function psLoadOps(){var po=$('#ps_production_id').val();if(!po){$('#ps_ops_area').html('<div class="alert alert-info" style="margin:12px">Pilih Production Order untuk menampilkan operation.</div>');return;}$('#ps_ops_area').html('<div class="alert alert-info" style="margin:12px"><i class="fa fa-spinner fa-spin"></i> Memuat operation...</div>');$.post('<?=base_admin();?>modul/production_schedule/production_schedule_action.php?act=operations',{production_id:po,planned_start:$('#ps_planned_start').val()},function(html){$('#ps_ops_area').html(html);if($.fn.select2){$('.ps-shift').select2({width:'100%',allowClear:true});}}).fail(function(){psError(<?=prod_js('production_operation_load_failed', 'Operation failed to load.');?>);});}
function psSave(flag){$('#ps_submit').val(flag);if(!$('#ps_production_id').val()){psError('Production Order wajib dipilih.');return;}if($('#form_ps input[name="op_id[]"]').length<1){psError('Minimal satu operation wajib dijadwalkan.');return;}$.ajax({url:'<?=base_admin();?>modul/production_schedule/production_schedule_action.php?act=save',type:'POST',data:$('#form_ps').serialize(),dataType:'json',success:function(r){if(r.status==='good'){$('#modal_ps').modal('hide');dt_ps.draw(false);Swal.fire(<?=prod_js('common_success', 'Success');?>,'Production Schedule '+(r.schedule_no||'')+' tersimpan.','success');}else psError(r.error_message);},error:function(xhr){console.log(xhr.responseText);psError('Production Schedule gagal disimpan.');}});}
var dt_ps;
$(function(){if($.fn.datepicker){$('.ps-date').datepicker({format:'yyyy-mm-dd',autoclose:true,todayHighlight:true});$('.ps-date-input').datepicker({format:'yyyy-mm-dd',autoclose:true,todayHighlight:true});}if($.fn.select2){$('#filter_status,#filter_plant').select2({width:'100%',allowClear:true});$('#ps_production_id').select2({width:'100%',placeholder:<?=prod_js('production_search_production_order', 'Search Production Order...');?>,minimumInputLength:1,ajax:{url:'<?=base_admin();?>modul/production_schedule/production_schedule_action.php?act=production_search',type:'POST',dataType:'json',delay:250,data:function(p){return{term:p.term||''};},processResults:function(d){return{results:d.results||[]};}}});}
dt_ps=$('#dtb_production_schedule').DataTable({bProcessing:true,bServerSide:true,pageLength:25,ordering:false,dom:"<'row'<'col-sm-12'B>>"+"<'row'<'col-sm-6'l><'col-sm-6'f>>"+"<'row'<'col-sm-12'tr>>"+"<'row'<'col-sm-5'i><'col-sm-7'p>>",buttons:[{extend:'collection',text:<?=prod_js('common_export_data', 'Export Data');?>,buttons:['copyHtml5','excelHtml5','csvHtml5','pdfHtml5']}],columnDefs:[{targets:[0,1],orderable:false,searchable:false},{width:'38px',targets:0},{width:'125px',targets:1}],ajax:{url:'<?=base_admin();?>modul/production_schedule/production_schedule_data.php',type:'post',data:function(d){$.extend(d,psFilters());},error:function(xhr){console.log(xhr.responseText);psError(<?=prod_js('production_schedule_load_failed', 'Production Schedule data failed to load.');?>);}}});
$('#btn_filter_ps').click(function(){dt_ps.draw();});$('#filter_keyword,#filter_work_center').keyup(function(e){if(e.keyCode===13)dt_ps.draw();});$('#btn_reset_ps').click(function(){$('#filter_tgl_awal').val('<?=$defaultFrom;?>');$('#filter_tgl_akhir').val('<?=$defaultTo;?>');$('#filter_status,#filter_plant').val('').trigger('change');$('#filter_work_center,#filter_keyword').val('');dt_ps.draw();});$('#btn_excel_ps').click(function(){window.location='<?=base_admin();?>modul/production_schedule/production_schedule_action.php?act=excel&'+$.param(psFilters());});
$('#btn_add_ps').click(function(){document.getElementById('form_ps').reset();$('#ps_production_id').val(null).trigger('change');$('#ps_schedule_date').val('<?=date('Y-m-d');?>');$('#ps_planned_start').val('<?=date('Y-m-d');?>T08:00');$('#ps_planned_finish').val('<?=date('Y-m-d');?>T17:00');$('#ps_ops_area').html('<div class="alert alert-info" style="margin:12px">Pilih Production Order untuk menampilkan operation.</div>');$('#modal_ps').modal({backdrop:'static',keyboard:false});});$('#ps_production_id,#ps_planned_start,#btn_reload_ops_ps').on('change click',psLoadOps);$('#btn_save_draft_ps').click(function(){psSave('N');});$('#btn_submit_ps').click(function(){psSave('Y');});
$(document).on('click','.btn-ps-detail',function(){$.post('<?=base_admin();?>modul/production_schedule/production_schedule_action.php?act=detail',{id:$(this).data('id')},function(html){$('#ps_detail_body').html(html);$('#modal_detail_ps').modal('show');}).fail(function(){psError('Detail gagal dibuka.');});});
$(document).on('click','.btn-ps-status',function(){var id=$(this).data('id'),act=$(this).data('act');Swal.fire({title:'Konfirmasi',text:'Lanjutkan aksi '+act+'?',icon:'question',showCancelButton:true,confirmButtonText:'Ya'}).then(function(x){if(!x.isConfirmed)return;$.post('<?=base_admin();?>modul/production_schedule/production_schedule_action.php?act='+act,{id:id},function(r){if(r.status==='good'){dt_ps.draw(false);Swal.fire(<?=prod_js('common_success', 'Success');?>,'Status diperbarui.','success');}else psError(r.error_message);},'json').fail(function(){psError('Status gagal diperbarui.');});});});
$(document).on('click','.btn-ps-cancel',function(){var id=$(this).data('id');Swal.fire({title:'Cancel Production Schedule',input:'text',inputLabel:'Alasan cancel',showCancelButton:true,confirmButtonText:'Cancel Schedule'}).then(function(x){if(!x.isConfirmed)return;$.post('<?=base_admin();?>modul/production_schedule/production_schedule_action.php?act=cancel',{id:id,reason:x.value||''},function(r){if(r.status==='good'){dt_ps.draw(false);Swal.fire(<?=prod_js('common_success', 'Success');?>,'Schedule dibatalkan.','success');}else psError(r.error_message);},'json').fail(function(){psError(<?=prod_js('production_cancel_process_failed', 'Cancel failed to process.');?>);});});});$('.hide_alert_notif').click(function(){$('.error_data_delete').hide();});
});
</script>
